import { existsSync, readFileSync } from "node:fs";

type Mode = "dry-run" | "apply";

type Check = {
	name: string;
	ok: boolean;
	detail: string;
};

type PlannedChange = {
	kind: string;
	target: string;
	action: string;
	reason: string;
	requiresUserConfirmation: boolean;
	wouldWrite: boolean;
};

type SeedResponseSummary = {
	status: number | null;
	contentType: string | null;
	classification: string;
	objectKeys?: string[];
	seeded?: boolean;
	accountIdPresent?: boolean;
	updatedAt?: string;
	error?: string;
	snippets?: string[];
};

type HealthResponseSummary = {
	status: number | null;
	contentType: string | null;
	classification: string;
	ok?: boolean;
	needsReauth?: boolean;
	upstreamStatus?: number | null;
	err?: string;
	snippets?: string[];
	responseBodyPresent?: boolean;
};

type ParsedArgs =
	| {
			ok: true;
			mode: Mode;
			url: string;
			useRootPassword: boolean;
			apply: boolean;
			yes: boolean;
	  }
	| { ok: false; error: string };

type RootPassword = { value: string; source: "process" | ".env.local" };

const REQUEST_TIMEOUT_MS = 12_000;
const BODY_SNIPPET_MAX_LENGTH = 220;

function emit(report: Report, exitCode = 0) {
	process.stdout.write(`${JSON.stringify(report, null, 2)}\n`);
	process.exitCode = exitCode;
}

type Facts = {
	input: {
		providedUrl: string | null;
		normalizedBaseUrl: string | null;
		applyRequested: boolean;
		yesFlagPresent: boolean;
		useRootPasswordRequested: boolean;
	};
	rootPassword: {
		available: boolean;
		source: "process" | ".env.local" | "missing";
		availableWithOptIn: boolean;
	};
	requests: {
		seedFromEnv: string | null;
		healthCheck: string | null;
	};
};

type Report = {
	ok: boolean;
	mode: Mode;
	phase: "seed-codex";
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	response?: {
		seed?: SeedResponseSummary;
		health?: HealthResponseSummary;
	};
	error?: string;
};

export function parseArgs(argv: string[]): ParsedArgs {
	const args = argv.slice(2);
	if (args[0] === "--") {
		args.shift();
	}

	let url = "";
	let useRootPassword = false;
	let apply = false;
	let yes = false;

	for (let index = 0; index < args.length; index += 1) {
		const arg = args[index];
		if (arg === "--url") {
			const value = args[index + 1];
			if (!value) {
				return { ok: false, error: "The --url argument requires a value." };
			}
			url = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--url=")) {
			url = arg.slice("--url=".length);
			continue;
		}

		if (arg === "--dry-run") {
			continue;
		}

		if (arg === "--use-root-password") {
			useRootPassword = true;
			continue;
		}

		if (arg === "--apply") {
			apply = true;
			continue;
		}

		if (arg === "--yes") {
			yes = true;
			continue;
		}

		return { ok: false, error: `Unsupported argument: ${arg}` };
	}

	if (!url.trim()) {
		return { ok: false, error: "Missing required --url argument." };
	}

	if (apply !== yes) {
		return {
			ok: false,
			error:
				"Unsupported argument combination. Use neither flag for dry-run or both --apply and --yes.",
		};
	}

	return {
		ok: true,
		mode: apply ? "apply" : "dry-run",
		url,
		useRootPassword,
		apply,
		yes,
	};
}

function readEnvLocalValue(key: string) {
	const envLocal = ".env.local";
	if (!existsSync(envLocal)) {
		return "";
	}

	const content = readFileSync(envLocal, "utf8");
	for (const rawLine of content.split(/\r?\n/)) {
		const trimmedLine = rawLine.trim();
		if (!trimmedLine || trimmedLine.startsWith("#")) {
			continue;
		}

		const normalized = trimmedLine.startsWith("export ")
			? trimmedLine.slice(7).trim()
			: trimmedLine;
		const equalsIndex = normalized.indexOf("=");
		if (equalsIndex <= 0) {
			continue;
		}

		const parsedKey = normalized.slice(0, equalsIndex).trim();
		const parsedValue = normalized.slice(equalsIndex + 1).trim();
		if (parsedKey === key && parsedValue) {
			return parsedValue;
		}
	}

	return "";
}

export function resolveRootPassword(): RootPassword | null {
	const fromProcess = process.env.ROOT_PASSWORD?.trim();
	if (fromProcess) {
		return { value: fromProcess, source: "process" };
	}

	const fromLocal = readEnvLocalValue("ROOT_PASSWORD");
	if (fromLocal) {
		return { value: fromLocal, source: ".env.local" };
	}

	return null;
}

export function normalizeBaseUrl(rawUrl: string): string {
	const parsed = new URL(rawUrl);
	const pathname = parsed.pathname.replace(/\/+$/, "");
	return `${parsed.protocol}//${parsed.host}${pathname}`;
}

export function buildSeedEndpoints(baseUrl: string): {
	seedFromEnv: string;
	healthCheck: string;
} {
	return {
		seedFromEnv: `${baseUrl}/api/v1/admin/codex-chatgpt-credentials/seed-from-env`,
		healthCheck: `${baseUrl}/api/v1/admin/codex-chatgpt-credentials/health-check`,
	};
}

export function classifyStatus(status: number): string {
	if (status >= 200 && status < 300) return "ok";
	if (status === 401) return "unauthorized";
	if (status === 403) return "forbidden";
	if (status === 404) return "not-found";
	if (status === 400) return "validation-error";
	if (status >= 500) return "server-error";
	return `status-${status}`;
}

export function summarizeErrorSnippets(value: unknown): string[] {
	if (!value || typeof value !== "object" || Array.isArray(value)) {
		return [];
	}

	const safeKeys = ["error", "detail", "message", "statusText"] as const;
	const result: string[] = [];

	for (const key of safeKeys) {
		const raw = value[key];
		if (typeof raw === "string") {
			const snippet = raw.trim().replace(/\s+/g, " ");
			if (snippet.length > 0 && snippet.length <= BODY_SNIPPET_MAX_LENGTH) {
				result.push(`${key}: ${snippet}`);
			}
		}
	}

	return result;
}

function safeRecord(value: unknown): Record<string, unknown> | null {
	if (value && typeof value === "object" && !Array.isArray(value)) {
		return value as Record<string, unknown>;
	}
	return null;
}

function summarizeSeedResponse(args: {
	status: number | null;
	contentType: string | null;
	summary: {
		seeded?: unknown;
		accountIdPresent?: unknown;
		updatedAt?: unknown;
		error?: unknown;
		detail?: unknown;
	};
	error?: string;
}): SeedResponseSummary {
	const record = safeRecord(args.summary);
	const snippets = record ? summarizeErrorSnippets(record) : [];
	const summary: SeedResponseSummary = {
		status: args.status,
		contentType: args.contentType,
		classification:
			args.status === null ? "network-error" : classifyStatus(args.status),
	};

	if (typeof args.summary.seeded === "boolean") {
		summary.seeded = args.summary.seeded;
	}
	if (typeof args.summary.accountIdPresent === "boolean") {
		summary.accountIdPresent = args.summary.accountIdPresent;
	}
	if (typeof args.summary.updatedAt === "string") {
		summary.updatedAt = args.summary.updatedAt;
	}
	if (snippets.length > 0) {
		summary.snippets = snippets;
	}

	if (typeof args.error === "string") {
		summary.error = args.error;
	}

	if (record) {
		summary.objectKeys = Object.keys(record).slice(0, 16);
	}

	return summary;
}

function summarizeHealthResponse(args: {
	status: number | null;
	contentType: string | null;
	value: unknown;
	error?: string;
}): HealthResponseSummary {
	const record = safeRecord(args.value);
	const snippets = record ? summarizeErrorSnippets(record) : [];
	const summary: HealthResponseSummary = {
		status: args.status,
		contentType: args.contentType,
		classification:
			args.status === null ? "network-error" : classifyStatus(args.status),
		responseBodyPresent: Boolean(record || (args.status !== null && args.value)),
	};

	if (record) {
		const ok = record.ok;
		const needsReauth = record.needsReauth;
		summary.objectKeys = Object.keys(record);
		if (typeof ok === "boolean") {
			summary.ok = ok;
		}
		if (typeof needsReauth === "boolean") {
			summary.needsReauth = needsReauth;
		}
		const upstreamStatus = record.upstreamStatus;
		if (typeof upstreamStatus === "number") {
			summary.upstreamStatus = upstreamStatus;
		}
	}

	if (typeof args.error === "string") {
		summary.err = args.error;
	}
	if (snippets.length > 0) {
		summary.snippets = snippets;
	}

	return summary;
}

function summarizeNetworkError(error: unknown): string {
	return error instanceof Error
		? `network error: ${error.message}`
		: `network error: ${String(error)}`;
}

async function callSeedFromEnv(args: {
	endpoint: string;
	token: string;
}): Promise<
	| {
		status: number | null;
		contentType: string | null;
		seeded?: unknown;
		accountIdPresent?: unknown;
		updatedAt?: unknown;
		error?: string;
		objectKeys?: string[];
	}
> {
	const controller = new AbortController();
	const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

	try {
		const response = await fetch(args.endpoint, {
			method: "POST",
			headers: { Authorization: `Bearer ${args.token}` },
			redirect: "manual",
			signal: controller.signal,
		});
		const contentType = response.headers.get("content-type");
		if (!contentType?.includes("application/json")) {
			return {
				status: response.status,
				contentType,
				error: "non-json response received",
			};
		}

		try {
			const body = (await response.json()) as unknown;
			if (!body || typeof body !== "object" || Array.isArray(body)) {
				return { status: response.status, contentType };
			}
			const record = body as Record<string, unknown>;
			return {
				status: response.status,
				contentType,
				seeded: record.seeded,
				accountIdPresent: record.accountIdPresent,
				updatedAt: record.updatedAt,
				objectKeys: Object.keys(record),
			};
		} catch (error) {
			return {
				status: response.status,
				contentType,
				error:
					error instanceof Error
						? error.message
						: "failed to parse JSON response",
			};
		}
	} catch (error) {
		return {
			status: null,
			contentType: null,
			error: summarizeNetworkError(error),
		};
	} finally {
		clearTimeout(timeout);
	}
}

async function callHealthCheck(args: {
	endpoint: string;
	token: string;
}): Promise<
	| {
		status: number | null;
		contentType: string | null;
		value: unknown;
		error?: string;
	}
> {
	const controller = new AbortController();
	const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

	try {
		const response = await fetch(args.endpoint, {
			method: "POST",
			headers: { Authorization: `Bearer ${args.token}` },
			redirect: "manual",
			signal: controller.signal,
		});
		const contentType = response.headers.get("content-type");
		if (!contentType?.includes("application/json")) {
			return {
				status: response.status,
				contentType,
				value: null,
				error: "non-json response received",
			};
		}

		try {
			const value = await response.json();
			return {
				status: response.status,
				contentType,
				value,
			};
		} catch (error) {
			return {
				status: response.status,
				contentType,
				value: null,
				error:
					error instanceof Error
						? error.message
						: "failed to parse JSON response",
			};
		 }
	} catch (error) {
		return {
			status: null,
			contentType: null,
			value: null,
			error: summarizeNetworkError(error),
		};
	} finally {
		clearTimeout(timeout);
	}
}

function reportBase(input: {
	ok: boolean;
	mode: Mode;
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	response?: { seed?: SeedResponseSummary; health?: HealthResponseSummary };
	error?: string;
}): Report {
	return {
		ok: input.ok,
		mode: input.mode,
		phase: "seed-codex",
		facts: input.facts,
		checks: input.checks,
		plannedChanges: input.plannedChanges,
		needsUser: input.needsUser,
		blocked: input.blocked,
		nextActions: input.nextActions,
		...(input.response ? { response: input.response } : {}),
		...(input.error ? { error: input.error } : {}),
	};
}

function invalidArgsError(message: string) {
	emit(
		reportBase({
			ok: false,
			mode: "dry-run",
			facts: {
				input: {
					providedUrl: null,
					normalizedBaseUrl: null,
					applyRequested: false,
					yesFlagPresent: false,
					useRootPasswordRequested: false,
				},
				rootPassword: {
					available: false,
					source: "missing",
					availableWithOptIn: false,
				},
				requests: {
					seedFromEnv: null,
					healthCheck: null,
				},
			},
			checks: [],
			plannedChanges: [],
			needsUser: [
				"Provide --url <https://...>. Use --apply --yes --use-root-password to run live calls.",
			],
			blocked: ["Unsupported or invalid arguments."],
			nextActions: [
				"Supported args: --url, optional --dry-run, or exact --apply --yes --use-root-password.",
			],
			error: message,
		}),
		1,
	);
}

async function main() {
	const parsed = parseArgs(process.argv);
	if (!parsed.ok) {
		invalidArgsError(parsed.error);
		return;
	}

	let normalizedBaseUrl: string | null = null;
	try {
		normalizedBaseUrl = normalizeBaseUrl(parsed.url);
	} catch {
		normalizedBaseUrl = null;
	}

	const endpoints = normalizedBaseUrl
		? buildSeedEndpoints(normalizedBaseUrl)
		: { seedFromEnv: null, healthCheck: null };

	const rootPassword = parsed.useRootPassword ? resolveRootPassword() : null;
	const rootPasswordSource = rootPassword?.source ?? "missing";
	const rootPasswordAvailable = Boolean(rootPassword);

	const facts: Facts = {
		input: {
			providedUrl: parsed.url,
			normalizedBaseUrl,
			applyRequested: parsed.apply,
			yesFlagPresent: parsed.yes,
			useRootPasswordRequested: parsed.useRootPassword,
		},
		rootPassword: {
			available: parsed.useRootPassword ? rootPasswordAvailable : false,
			source: parsed.useRootPassword ? rootPasswordSource : "missing",
			availableWithOptIn: rootPasswordAvailable && parsed.useRootPassword,
		},
		requests: {
			seedFromEnv: endpoints.seedFromEnv,
			healthCheck: endpoints.healthCheck,
		},
	};

	if (!normalizedBaseUrl) {
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts: {
					...facts,
					input: {
						...facts.input,
						normalizedBaseUrl: null,
					},
					requests: { seedFromEnv: null, healthCheck: null },
				},
				checks: [
					{
						name: "preview-url",
						ok: false,
						detail: "must include valid URL scheme and host",
					},
				],
				plannedChanges: [
					{
						kind: "seed-codex",
						target: `${parsed.url}/api/v1/admin/codex-chatgpt-credentials/seed-from-env`,
						action: "POST seed request + POST health-check",
						reason:
							"Dry-run cannot target an invalid URL.",
						requiresUserConfirmation: true,
						wouldWrite: false,
					},
				],
				needsUser: [
					"Provide a valid URL. Example: --url https://preview.app.vercel.app",
				],
				blocked: ["Invalid --url value."],
				nextActions: ["Rerun with a valid preview URL."],
			}),
			1,
		);
		return;
	}

	const checks: Check[] = [];
	const needsUser: string[] = [];
	const blocked: string[] = [];
	const nextActions: string[] = [];
	const plannedChanges: PlannedChange[] = [
		{
			kind: "seed-codex",
			target: endpoints.seedFromEnv,
			action: "POST { authorization: bearer }",
			reason: "Seed Mediator credential state from INITIAL_CHATGPT_AUTH_JSON already present on deploy env.",
			requiresUserConfirmation: true,
			wouldWrite: parsed.apply,
		},
		{
			kind: "seed-codex-health",
			target: endpoints.healthCheck,
			action: "POST { authorization: bearer }",
			reason:
				"Immediately confirm credential health after seeding before first scheduler attempt.",
			requiresUserConfirmation: true,
			wouldWrite: parsed.apply,
		},
	];

	checks.push({
		name: "seed-endpoint",
		ok: Boolean(endpoints.seedFromEnv),
		detail: "seed endpoint planned",
	});

	if (!parsed.useRootPassword) {
		needsUser.push(
			"Pass --use-root-password to authorize seed + health-check calls with ROOT_PASSWORD.",
		);
		nextActions.push(
			"Dry-run only. Rerun with --apply --yes --use-root-password to run the safe seed and health check.",
		);
	} else if (!parsed.apply) {
		nextActions.push(
			"Rerun with --apply --yes --use-root-password to execute this mutation safely.",
		);
	}

	if (parsed.apply) {
		if (!parsed.useRootPassword) {
			blocked.push("Apply requires --use-root-password.");
		}
		if (!rootPasswordAvailable) {
			blocked.push("ROOT_PASSWORD is missing.");
			needsUser.push(
				"Set ROOT_PASSWORD in process env or .env.local before applying.",
			);
			checks.push({
				name: "root-password",
				ok: false,
				detail: "missing",
			});
		}
	}

	if (parsed.mode === "dry-run") {
		emit(
			reportBase({
				ok: blocked.length === 0,
				mode: parsed.mode,
				facts,
				checks: rootPasswordAvailable
					? [
						{
							name: "root-password",
							ok: rootPasswordAvailable,
							detail: `available from ${rootPasswordSource}`,
						},
					]
					: checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
			}),
		);
		return;
	}

	if (blocked.length > 0) {
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts,
				checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
				error: "Apply blocked by required operator inputs.",
			}),
			1,
		);
		return;
	}

	const seedResult = await callSeedFromEnv({
		endpoint: endpoints.seedFromEnv,
		token: rootPassword!.value,
	});
	const seedSummary = summarizeSeedResponse({
		status: seedResult.status,
		contentType: seedResult.contentType,
		summary: {
			seeded: seedResult.seeded,
			accountIdPresent: seedResult.accountIdPresent,
			updatedAt: seedResult.updatedAt,
			error: "",
			detail: "",
		},
		error: seedResult.error,
	});

	const response: { seed?: SeedResponseSummary; health?: HealthResponseSummary } = {
		seed: seedSummary,
	};

	if (seedSummary.classification !== "ok") {
		blocked.push("Seed request failed; health check was not run.");
		nextActions.push(
			"Fix the seed failure (auth, validation, or endpoint issue), then rerun.",
		);
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts,
				checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
				response,
				error: "Seed request did not succeed.",
			}),
			1,
		);
		return;
	}

	const healthResult = await callHealthCheck({
		endpoint: endpoints.healthCheck,
		token: rootPassword.value,
	});
	response.health = summarizeHealthResponse({
		status: healthResult.status,
		contentType: healthResult.contentType,
		value: healthResult.value,
		error: healthResult.error,
	});

	const ok = response.health.classification === "ok";
	nextActions.push(
		ok
			? "Health check succeeded. Continue to first issue handoff with setup:first-issue."
			: "Seed was applied, but health check failed; review response and retry after addressing refresh-state issues.",
	);

	emit(
		reportBase({
			ok,
			mode: parsed.mode,
			facts,
			checks,
			plannedChanges,
			needsUser,
			blocked,
			nextActions,
			response,
		}),
		ok ? 0 : 1,
	);
}

main();
EOF"}

