import { existsSync, readFileSync } from "node:fs";

type Mode = "dry-run" | "apply";

type Check = {
	name: string;
	ok: boolean;
	detail: string;
};

type PlannedChange = {
	kind: string;
	target: string;
	action: string;
	reason: string;
	requiresUserConfirmation: boolean;
	wouldWrite: boolean;
};

type SeedResponseSummary = {
	status: number | null;
	contentType: string | null;
	classification: string;
	objectKeys?: string[];
	seeded?: boolean;
	accountIdPresent?: boolean;
	updatedAt?: string;
	error?: string;
	snippets?: string[];
};

type HealthResponseSummary = {
	status: number | null;
	contentType: string | null;
	classification: string;
	ok?: boolean;
	needsReauth?: boolean;
	upstreamStatus?: number | null;
	err?: string;
	snippets?: string[];
	responseBodyPresent?: boolean;
};

type ParsedArgs =
	| {
			ok: true;
			mode: Mode;
			url: string;
			useRootPassword: boolean;
			apply: boolean;
			yes: boolean;
	  }
	| { ok: false; error: string };

type RootPassword = { value: string; source: "process" | ".env.local" };

const REQUEST_TIMEOUT_MS = 12_000;
const BODY_SNIPPET_MAX_LENGTH = 220;

function emit(report: Report, exitCode = 0) {
	process.stdout.write(`${JSON.stringify(report, null, 2)}\n`);
	process.exitCode = exitCode;
}

type Facts = {
	input: {
		providedUrl: string | null;
		normalizedBaseUrl: string | null;
		applyRequested: boolean;
		yesFlagPresent: boolean;
		useRootPasswordRequested: boolean;
	};
	rootPassword: {
		available: boolean;
		source: "process" | ".env.local" | "missing";
		availableWithOptIn: boolean;
	};
	requests: {
		seedFromEnv: string | null;
		healthCheck: string | null;
	};
};

type Report = {
	ok: boolean;
	mode: Mode;
	phase: "seed-codex";
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	response?: {
		seed?: SeedResponseSummary;
		health?: HealthResponseSummary;
	};
	error?: string;
};

export function parseArgs(argv: string[]): ParsedArgs {
	const args = argv.slice(2);
	if (args[0] === "--") {
		args.shift();
	}

	let url = "";
	let useRootPassword = false;
	let apply = false;
	let yes = false;

	for (let index = 0; index < args.length; index += 1) {
		const arg = args[index];
		if (arg === "--url") {
			const value = args[index + 1];
			if (!value) {
				return { ok: false, error: "The --url argument requires a value." };
			}
			url = value;
			index += 1;
			continue;
		}

		if (arg.startsWith("--url=")) {
			url = arg.slice("--url=".length);
			continue;
		}

		if (arg === "--dry-run") {
			continue;
		}

		if (arg === "--use-root-password") {
			useRootPassword = true;
			continue;
		}

		if (arg === "--apply") {
			apply = true;
			continue;
		}

		if (arg === "--yes") {
			yes = true;
			continue;
		}

		return { ok: false, error: `Unsupported argument: ${arg}` };
	}

	if (!url.trim()) {
		return { ok: false, error: "Missing required --url argument." };
	}

	if (apply !== yes) {
		return {
			ok: false,
			error:
				"Unsupported argument combination. Use neither flag for dry-run or both --apply and --yes.",
		};
	}

	return {
		ok: true,
		mode: apply ? "apply" : "dry-run",
		url,
		useRootPassword,
		apply,
		yes,
	};
}

function readEnvLocalValue(key: string) {
	const envLocal = ".env.local";
	if (!existsSync(envLocal)) {
		return "";
	}

	const content = readFileSync(envLocal, "utf8");
	for (const rawLine of content.split(/\r?\n/)) {
		const trimmedLine = rawLine.trim();
		if (!trimmedLine || trimmedLine.startsWith("#")) {
			continue;
		}

		const normalized = trimmedLine.startsWith("export ")
			? trimmedLine.slice(7).trim()
			: trimmedLine;
		const equalsIndex = normalized.indexOf("=");
		if (equalsIndex <= 0) {
			continue;
		}

		const parsedKey = normalized.slice(0, equalsIndex).trim();
		const parsedValue = normalized.slice(equalsIndex + 1).trim();
		if (parsedKey === key && parsedValue) {
			return parsedValue;
		}
	}

	return "";
}

export function resolveRootPassword(): RootPassword | null {
	const fromProcess = process.env.ROOT_PASSWORD?.trim();
	if (fromProcess) {
		return { value: fromProcess, source: "process" };
	}

	const fromLocal = readEnvLocalValue("ROOT_PASSWORD");
	if (fromLocal) {
		return { value: fromLocal, source: ".env.local" };
	}

	return null;
}

export function normalizeBaseUrl(rawUrl: string): string {
	const parsed = new URL(rawUrl);
	const pathname = parsed.pathname.replace(/\/+$/, "");
	return `${parsed.protocol}//${parsed.host}${pathname}`;
}

export function buildSeedEndpoints(baseUrl: string): {
	seedFromEnv: string;
	healthCheck: string;
} {
	return {
		seedFromEnv: `${baseUrl}/api/v1/admin/codex-chatgpt-credentials/seed-from-env`,
		healthCheck: `${baseUrl}/api/v1/admin/codex-chatgpt-credentials/health-check`,
	};
}

export function classifyStatus(status: number): string {
	if (status >= 200 && status < 300) return "ok";
	if (status === 401) return "unauthorized";
	if (status === 403) return "forbidden";
	if (status === 404) return "not-found";
	if (status === 400) return "validation-error";
	if (status >= 500) return "server-error";
	return `status-${status}`;
}

export function summarizeErrorSnippets(value: unknown): string[] {
	if (!value || typeof value !== "object" || Array.isArray(value)) {
		return [];
	}

	const safeKeys = ["error", "detail", "message", "statusText"] as const;
	const result: string[] = [];

	for (const key of safeKeys) {
		const raw = value[key];
		if (typeof raw === "string") {
			const snippet = raw.trim().replace(/\s+/g, " ");
			if (snippet.length > 0 && snippet.length <= BODY_SNIPPET_MAX_LENGTH) {
				result.push(`${key}: ${snippet}`);
			}
		}
	}

	return result;
}

function safeRecord(value: unknown): Record<string, unknown> | null {
	if (value && typeof value === "object" && !Array.isArray(value)) {
		return value as Record<string, unknown>;
	}
	return null;
}

function summarizeSeedResponse(args: {
	status: number | null;
	contentType: string | null;
	summary: {
		seeded?: unknown;
		accountIdPresent?: unknown;
		updatedAt?: unknown;
		error?: unknown;
		detail?: unknown;
	};
	error?: string;
}): SeedResponseSummary {
	const record = safeRecord(args.summary);
	const snippets = record ? summarizeErrorSnippets(record) : [];
	const summary: SeedResponseSummary = {
		status: args.status,
		contentType: args.contentType,
		classification:
			args.status === null ? "network-error" : classifyStatus(args.status),
	};

	if (typeof args.summary.seeded === "boolean") {
		summary.seeded = args.summary.seeded;
	}
	if (typeof args.summary.accountIdPresent === "boolean") {
		summary.accountIdPresent = args.summary.accountIdPresent;
	}
	if (typeof args.summary.updatedAt === "string") {
		summary.updatedAt = args.summary.updatedAt;
	}
	if (snippets.length > 0) {
		summary.snippets = snippets;
	}

	if (typeof args.error === "string") {
		summary.error = args.error;
	}

	if (record) {
		summary.objectKeys = Object.keys(record).slice(0, 16);
	}

	return summary;
}

function summarizeHealthResponse(args: {
	status: number | null;
	contentType: string | null;
	value: unknown;
	error?: string;
}): HealthResponseSummary {
	const record = safeRecord(args.value);
	const snippets = record ? summarizeErrorSnippets(record) : [];
	const summary: HealthResponseSummary = {
		status: args.status,
		contentType: args.contentType,
		classification:
			args.status === null ? "network-error" : classifyStatus(args.status),
		responseBodyPresent: Boolean(record || (args.status !== null && args.value)),
	};

	if (record) {
		const ok = record.ok;
		const needsReauth = record.needsReauth;
		summary.objectKeys = Object.keys(record);
		if (typeof ok === "boolean") {
			summary.ok = ok;
		}
		if (typeof needsReauth === "boolean") {
			summary.needsReauth = needsReauth;
		}
		const upstreamStatus = record.upstreamStatus;
		if (typeof upstreamStatus === "number") {
			summary.upstreamStatus = upstreamStatus;
		}
	}

	if (typeof args.error === "string") {
		summary.err = args.error;
	}
	if (snippets.length > 0) {
		summary.snippets = snippets;
	}

	return summary;
}

function summarizeNetworkError(error: unknown): string {
	return error instanceof Error
		? `network error: ${error.message}`
		: `network error: ${String(error)}`;
}

async function callSeedFromEnv(args: {
	endpoint: string;
	token: string;
}): Promise<
	| {
		status: number | null;
		contentType: string | null;
		seeded?: unknown;
