async function callHealthCheck(args: {
	endpoint: string;
	token: string;
}): Promise<
	| {
		status: number | null;
		contentType: string | null;
		value: unknown;
		error?: string;
	}
> {
	const controller = new AbortController();
	const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

	try {
		const response = await fetch(args.endpoint, {
			method: "POST",
			headers: { Authorization: `Bearer ${args.token}` },
			redirect: "manual",
			signal: controller.signal,
		});
		const contentType = response.headers.get("content-type");
		if (!contentType?.includes("application/json")) {
			return {
				status: response.status,
				contentType,
				value: null,
				error: "non-json response received",
			};
		}

		try {
			const value = await response.json();
			return {
				status: response.status,
				contentType,
				value,
			};
		} catch (error) {
			return {
				status: response.status,
				contentType,
				value: null,
				error:
					error instanceof Error
						? error.message
						: "failed to parse JSON response",
			};
		 }
	} catch (error) {
		return {
			status: null,
			contentType: null,
			value: null,
			error: summarizeNetworkError(error),
		};
	} finally {
		clearTimeout(timeout);
	}
}

function reportBase(input: {
	ok: boolean;
	mode: Mode;
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
	response?: { seed?: SeedResponseSummary; health?: HealthResponseSummary };
	error?: string;
}): Report {
	return {
		ok: input.ok,
		mode: input.mode,
		phase: "seed-codex",
		facts: input.facts,
		checks: input.checks,
		plannedChanges: input.plannedChanges,
		needsUser: input.needsUser,
		blocked: input.blocked,
		nextActions: input.nextActions,
		...(input.response ? { response: input.response } : {}),
		...(input.error ? { error: input.error } : {}),
	};
}

function invalidArgsError(message: string) {
	emit(
		reportBase({
			ok: false,
			mode: "dry-run",
			facts: {
				input: {
					providedUrl: null,
					normalizedBaseUrl: null,
					applyRequested: false,
					yesFlagPresent: false,
					useRootPasswordRequested: false,
				},
				rootPassword: {
					available: false,
					source: "missing",
					availableWithOptIn: false,
				},
				requests: {
					seedFromEnv: null,
					healthCheck: null,
				},
			},
			checks: [],
			plannedChanges: [],
			needsUser: [
				"Provide --url <https://...>. Use --apply --yes --use-root-password to run live calls.",
			],
			blocked: ["Unsupported or invalid arguments."],
			nextActions: [
				"Supported args: --url, optional --dry-run, or exact --apply --yes --use-root-password.",
			],
			error: message,
		}),
		1,
	);
}

async function main() {
	const parsed = parseArgs(process.argv);
	if (!parsed.ok) {
		invalidArgsError(parsed.error);
		return;
	}

	let normalizedBaseUrl: string | null = null;
	try {
		normalizedBaseUrl = normalizeBaseUrl(parsed.url);
	} catch {
		normalizedBaseUrl = null;
	}

	const endpoints = normalizedBaseUrl
		? buildSeedEndpoints(normalizedBaseUrl)
		: { seedFromEnv: null, healthCheck: null };

	const rootPassword = parsed.useRootPassword ? resolveRootPassword() : null;
	const rootPasswordSource = rootPassword?.source ?? "missing";
	const rootPasswordAvailable = Boolean(rootPassword);

	const facts: Facts = {
		input: {
			providedUrl: parsed.url,
			normalizedBaseUrl,
			applyRequested: parsed.apply,
			yesFlagPresent: parsed.yes,
			useRootPasswordRequested: parsed.useRootPassword,
		},
		rootPassword: {
			available: parsed.useRootPassword ? rootPasswordAvailable : false,
			source: parsed.useRootPassword ? rootPasswordSource : "missing",
			availableWithOptIn: rootPasswordAvailable && parsed.useRootPassword,
		},
		requests: {
			seedFromEnv: endpoints.seedFromEnv,
			healthCheck: endpoints.healthCheck,
		},
	};

	if (!normalizedBaseUrl) {
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts: {
					...facts,
					input: {
						...facts.input,
						normalizedBaseUrl: null,
					},
					requests: { seedFromEnv: null, healthCheck: null },
				},
				checks: [
					{
						name: "preview-url",
						ok: false,
						detail: "must include valid URL scheme and host",
					},
				],
				plannedChanges: [
					{
						kind: "seed-codex",
						target: `${parsed.url}/api/v1/admin/codex-chatgpt-credentials/seed-from-env`,
						action: "POST seed request + POST health-check",
						reason:
							"Dry-run cannot target an invalid URL.",
						requiresUserConfirmation: true,
						wouldWrite: false,
					},
				],
				needsUser: [
					"Provide a valid URL. Example: --url https://preview.app.vercel.app",
				],
				blocked: ["Invalid --url value."],
				nextActions: ["Rerun with a valid preview URL."],
			}),
			1,
		);
		return;
	}

	const checks: Check[] = [];
	const needsUser: string[] = [];
	const blocked: string[] = [];
	const nextActions: string[] = [];
	const plannedChanges: PlannedChange[] = [
		{
			kind: "seed-codex",
			target: endpoints.seedFromEnv,
			action: "POST { authorization: bearer }",
			reason: "Seed Mediator credential state from INITIAL_CHATGPT_AUTH_JSON already present on deploy env.",
			requiresUserConfirmation: true,
			wouldWrite: parsed.apply,
		},
		{
			kind: "seed-codex-health",
			target: endpoints.healthCheck,
			action: "POST { authorization: bearer }",
			reason:
				"Immediately confirm credential health after seeding before first scheduler attempt.",
			requiresUserConfirmation: true,
			wouldWrite: parsed.apply,
		},
	];

	checks.push({
		name: "seed-endpoint",
		ok: Boolean(endpoints.seedFromEnv),
		detail: "seed endpoint planned",
	});

	if (!parsed.useRootPassword) {
		needsUser.push(
			"Pass --use-root-password to authorize seed + health-check calls with ROOT_PASSWORD.",
		);
		nextActions.push(
			"Dry-run only. Rerun with --apply --yes --use-root-password to run the safe seed and health check.",
		);
	} else if (!parsed.apply) {
		nextActions.push(
			"Rerun with --apply --yes --use-root-password to execute this mutation safely.",
		);
	}

	if (parsed.apply) {
		if (!parsed.useRootPassword) {
			blocked.push("Apply requires --use-root-password.");
		}
		if (!rootPasswordAvailable) {
			blocked.push("ROOT_PASSWORD is missing.");
			needsUser.push(
				"Set ROOT_PASSWORD in process env or .env.local before applying.",
			);
			checks.push({
				name: "root-password",
				ok: false,
				detail: "missing",
			});
		}
	}

	if (parsed.mode === "dry-run") {
		emit(
			reportBase({
				ok: blocked.length === 0,
				mode: parsed.mode,
				facts,
				checks: rootPasswordAvailable
					? [
						{
							name: "root-password",
							ok: rootPasswordAvailable,
							detail: `available from ${rootPasswordSource}`,
						},
					]
					: checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
			}),
		);
		return;
	}

	if (blocked.length > 0) {
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts,
				checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
				error: "Apply blocked by required operator inputs.",
			}),
			1,
		);
		return;
	}

	const seedResult = await callSeedFromEnv({
		endpoint: endpoints.seedFromEnv,
		token: rootPassword!.value,
	});
	const seedSummary = summarizeSeedResponse({
		status: seedResult.status,
		contentType: seedResult.contentType,
		summary: {
			seeded: seedResult.seeded,
			accountIdPresent: seedResult.accountIdPresent,
			updatedAt: seedResult.updatedAt,
			error: "",
			detail: "",
		},
		error: seedResult.error,
	});

	const response: { seed?: SeedResponseSummary; health?: HealthResponseSummary } = {
		seed: seedSummary,
	};

	if (seedSummary.classification !== "ok") {
		blocked.push("Seed request failed; health check was not run.");
		nextActions.push(
			"Fix the seed failure (auth, validation, or endpoint issue), then rerun.",
		);
		emit(
			reportBase({
				ok: false,
				mode: parsed.mode,
				facts,
				checks,
				plannedChanges,
				needsUser,
				blocked,
				nextActions,
				response,
				error: "Seed request did not succeed.",
			}),
			1,
		);
		return;
	}

	const healthResult = await callHealthCheck({
		endpoint: endpoints.healthCheck,
		token: rootPassword.value,
	});
	response.health = summarizeHealthResponse({
		status: healthResult.status,
		contentType: healthResult.contentType,
		value: healthResult.value,
		error: healthResult.error,
	});

	const ok = response.health.classification === "ok";
	nextActions.push(
		ok
			? "Health check succeeded. Continue to first issue handoff with setup:first-issue."
			: "Seed was applied, but health check failed; review response and retry after addressing refresh-state issues.",
	);

	emit(
		reportBase({
			ok,
			mode: parsed.mode,
			facts,
			checks,
			plannedChanges,
			needsUser,
			blocked,
			nextActions,
			response,
		}),
		ok ? 0 : 1,
	);
}

main();

